# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.
# Category: race_condition

import akka.actor.{Actor, ActorRef, ActorSystem, Props}

// Message protocol
sealed trait BankMessage
case class Deposit(amount: BigDecimal, replyTo: Option[ActorRef] = None) extends BankMessage
case class Withdraw(amount: BigDecimal, replyTo: Option[ActorRef] = None) extends BankMessage
case object GetBalance extends BankMessage
case class BalanceResponse(balance: BigDecimal)
case class TransactionResult(success: Boolean, message: String, currentBalance: BigDecimal)

// Account Actor - Akka actors process messages one at a time from their mailbox,
// so the var is safely accessed sequentially by design. No synchronization needed
// because the actor model guarantees single-threaded message processing per actor.
class AccountActor(accountId: String, initialBalance: BigDecimal = BigDecimal(0)) extends Actor {

  // This var is safe here because Akka's actor model guarantees that only one message
  // is processed at a time per actor instance. The actor's mailbox serializes access.
  // Do NOT access this var from outside the actor (e.g., via closing over it in a Future).
  private var balance: BigDecimal = initialBalance

  override def receive: Receive = {
    case Deposit(amount, replyTo) =>
      if (amount <= 0) {
        val result = TransactionResult(
          success = false,
          message = s"Invalid deposit amount: $amount. Must be positive.",
          currentBalance = balance
        )
        replyTo.getOrElse(sender()).tell(result, self)
      } else {
        balance += amount
        val result = TransactionResult(
          success = true,
          message = s"Deposited $amount to account $accountId.",
          currentBalance = balance
        )
        replyTo.getOrElse(sender()).tell(result, self)
      }

    case Withdraw(amount, replyTo) =>
      if (amount <= 0) {
        val result = TransactionResult(
          success = false,
          message = s"Invalid withdrawal amount: $amount. Must be positive.",
          currentBalance = balance
        )
        replyTo.getOrElse(sender()).tell(result, self)
      } else if (amount > balance) {
        val result = TransactionResult(
          success = false,
          message = s"Insufficient funds in account $accountId. Requested: $amount, Available: $balance.",
          currentBalance = balance
        )
        replyTo.getOrElse(sender()).tell(result, self)
      } else {
        balance -= amount
        val result = TransactionResult(
          success = true,
          message = s"Withdrew $amount from account $accountId.",
          currentBalance = balance
        )
        replyTo.getOrElse(sender()).tell(result, self)
      }

    case GetBalance =>
      sender() ! BalanceResponse(balance)
  }
}

object AccountActor {
  def props(accountId: String, initialBalance: BigDecimal = BigDecimal(0)): Props =
    Props(new AccountActor(accountId, initialBalance))
}

// Account Manager Actor - routes messages to the correct account actor
class AccountManagerActor extends Actor {

  private var accounts: Map[String, ActorRef] = Map.empty

  sealed trait ManagerMessage
  case class CreateAccount(accountId: String, initialBalance: BigDecimal = BigDecimal(0)) extends ManagerMessage
  case class AccountDeposit(accountId: String, amount: BigDecimal) extends ManagerMessage
  case class AccountWithdraw(accountId: String, amount: BigDecimal) extends ManagerMessage
  case class AccountGetBalance(accountId: String) extends ManagerMessage

  override def receive: Receive = {
    case CreateAccount(accountId, initialBalance) =>
      if (accounts.contains(accountId)) {
        sender() ! TransactionResult(false, s"Account $accountId already exists.", BigDecimal(0))
      } else {
        val accountRef = context.actorOf(AccountActor.props(accountId, initialBalance), s"account-$accountId")
        accounts += (accountId -> accountRef)
        sender() ! TransactionResult(true, s"Account $accountId created with balance $initialBalance.", initialBalance)
      }

    case AccountDeposit(accountId, amount) =>
      accounts.get(accountId) match {
        case Some(ref) => ref.forward(Deposit(amount))
        case None => sender() ! TransactionResult(false, s"Account $accountId not found.", BigDecimal(0))
      }

    case AccountWithdraw(accountId, amount) =>
      accounts.get(accountId) match {
        case Some(ref) => ref.forward(Withdraw(amount))
        case None => sender() ! TransactionResult(false, s"Account $accountId not found.", BigDecimal(0))
      }

    case AccountGetBalance(accountId) =>
      accounts.get(accountId) match {
        case Some(ref) => ref.forward(GetBalance)
        case None => sender() ! TransactionResult(false, s"Account $accountId not found.", BigDecimal(0))
      }
  }
}

object AccountManagerActor {
  def props: Props = Props(new AccountManagerActor)
}

// Demo application
object BankingApp extends App {
  import akka.pattern.ask
  import akka.util.Timeout
  import scala.concurrent.duration._
  import scala.concurrent.{Await, ExecutionContext}

  implicit val timeout: Timeout = Timeout(5.seconds)

  val system = ActorSystem("BankingSystem")
  implicit val ec: ExecutionContext = system.dispatcher

  // Create a single account actor for demonstration
  val account = system.actorOf(AccountActor.props("ACC-001", BigDecimal(1000)), "account-001")

  // Simulate concurrent transactions - all safely serialized by the actor's mailbox
  val futures = for (i <- 1 to 10) yield {
    if (i % 3 == 0)
      (account ? Withdraw(BigDecimal(50))).mapTo[TransactionResult]
    else
      (account ? Deposit(BigDecimal(100))).mapTo[TransactionResult]
  }

  val results = Await.result(
    scala.concurrent.Future.sequence(futures),
    10.seconds
  )

  results.foreach(r => println(s"[${if (r.success) "OK" else "FAIL"}] ${r.message} | Balance: ${r.currentBalance}"))

  // Final balance check
  val finalBalance = Await.result((account ? GetBalance).mapTo[BalanceResponse], 5.seconds)
  println(s"\nFinal balance: ${finalBalance.balance}")

  system.terminate()
}